const https = require('https');

// Test connectivity to Brave Search API
const result = await new Promise((resolve) => {
  const req = https.request({
    hostname: 'api.search.brave.com',
    port: 443,
    path: '/',
    method: 'HEAD',
    timeout: 5000
  }, (res) => {
    resolve({ online: true, statusCode: res.statusCode });
  });
  req.on('error', (e) => resolve({ online: false, reason: e.message }));
  req.on('timeout', () => {
    req.destroy();
    resolve({ online: false, reason: 'timeout' });
  });
  req.end();
});

const now = new Date();
const timeET = now.toLocaleString('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: false });

return [{ json: { ...result, checkedAt: now.toISOString(), timeET } }];

const fs = require('fs');

// Check if Orchestra has already run today
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/New_York' }); // YYYY-MM-DD
const flagDir = '/data/Aidan_Outputs/Orchestra';
const flagPath = `${flagDir}/ran_${today}.flag`;

fs.mkdirSync(flagDir, { recursive: true });

const alreadyRan = fs.existsSync(flagPath);

return [{ json: { alreadyRan, today, flagPath } }];

// Network is down — log silently and stop
const { reason, checkedAt, timeET } = $input.first().json;
console.log(`[Watchdog] Network offline at ${timeET} ET — ${reason || 'unknown'}. Will retry in 5 min.`);
return [{ json: { skipped: true, reason, checkedAt } }];

const fs = require('fs');
const http = require('http');
const { flagPath, today } = $input.first().json;

// Write flag file FIRST to prevent double-firing
fs.writeFileSync(flagPath, `Orchestra fired at ${new Date().toISOString()}`, 'utf8');

// Fire Orchestra
const body = JSON.stringify({
  command: 'morning brief',
  source: 'network-watchdog',
  date: today
});

const opts = {
  hostname: 'host.docker.internal',
  port: 5678,
  path: '/webhook/aidan-orchestra',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(body)
  }
};

const result = await new Promise((resolve) => {
  const req = http.request(opts, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ fired: true, status: res.statusCode, response: d }));
  });
  req.on('error', (e) => resolve({ fired: false, error: e.message }));
  req.write(body);
  req.end();
});

const timeET = new Date().toLocaleString('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: true });

return [{ json: { ...result, today, flagPath, firedAt: timeET } }];

// Already ran today — skip silently
const { today } = $input.first().json;
console.log(`[Watchdog] Orchestra already ran today (${today}). Skipping.`);
return [{ json: { skipped: true, reason: 'already_ran', today } }];

const http = require('http');
const { fired, firedAt, today, error } = $input.first().json;

if (!fired) {
  // Orchestra fire failed — send WhatsApp alert
  const alertMsg = `⚠️ WATCHDOG ALERT\nOrchestra failed to fire at ${firedAt} ET\nError: ${error || 'unknown'}\nManual trigger: say Orchestra`;
  const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: alertMsg } });
  const opts = {
    hostname: 'host.docker.internal',
    port: 8081,
    path: '/message/sendText/Aidan',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
  };
  await new Promise(r => {
    const req = http.request(opts, res => { res.on('data', () => {}); res.on('end', r); });
    req.on('error', r);
    req.write(msgBody);
    req.end();
  });
}

return [{ json: { success: fired, firedAt, today } }];
